/* Register dcregShLayer0DmaSramSize **
** ~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~ */

/* Each layer needs some sram when this layer works.  This register is used   **
** to specify the dma sram size for this layer.  Dma sram unit size has 64k   **
** bytes and 32k bytes size.  Dma sram unit size refers to                    **
** Vivante.*.Hardware.Architecture.and.Features.                              */

#define DCREG_SH_LAYER0_DMA_SRAM_SIZE_Address                           0x018290
#define DCREG_SH_LAYER0_DMA_SRAM_SIZE_Count                                    1
#define DCREG_SH_LAYER0_DMA_SRAM_SIZE_WriteMask                       0x0000FFFF
#define DCREG_SH_LAYER0_DMA_SRAM_SIZE_ResetValue                      0x00000000

/* 64KBytes: Specify 64k bytes sram size. 128KBytes: Specify 128k bytes sram  **
** size. 192KBytes: Specify 192k bytes sram size. 256KBytes: Specify 256k     **
** bytes sram size. 320KBytes: Specify 320k bytes sram size. 384KBytes:       **
** Specify 384k bytes sram size.                                              */
#define DCREG_SH_LAYER0_DMA_SRAM_SIZE_VALUE                                  7:0
#define   DCREG_SH_LAYER0_DMA_SRAM_SIZE_VALUE_KBYTE64                       0x00
#define   DCREG_SH_LAYER0_DMA_SRAM_SIZE_VALUE_KBYTE128                      0x01
#define   DCREG_SH_LAYER0_DMA_SRAM_SIZE_VALUE_KBYTE192                      0x02
#define   DCREG_SH_LAYER0_DMA_SRAM_SIZE_VALUE_KBYTE256                      0x03
#define   DCREG_SH_LAYER0_DMA_SRAM_SIZE_VALUE_KBYTE320                      0x04
#define   DCREG_SH_LAYER0_DMA_SRAM_SIZE_VALUE_KBYTE384                      0x05

/* 32KBytes: Specify 32k bytes sram size. 64KBytes: Specify 64k bytes sram    **
** size. 96KBytes: Specify 96k bytes sram size. 128KBytes: Specify 128k bytes **
** sram size. 160KBytes: Specify 160k bytes sram size. 192KBytes: Specify     **
** 192k bytes sram size.                                                      */
#define DCREG_SH_LAYER0_DMA_SRAM_SIZE_VALUE_EX                              15:8
#define   DCREG_SH_LAYER0_DMA_SRAM_SIZE_VALUE_EX_KBYTE32                    0x00
#define   DCREG_SH_LAYER0_DMA_SRAM_SIZE_VALUE_EX_KBYTE64                    0x01
#define   DCREG_SH_LAYER0_DMA_SRAM_SIZE_VALUE_EX_KBYTE96                    0x02
#define   DCREG_SH_LAYER0_DMA_SRAM_SIZE_VALUE_EX_KBYTE128                   0x03
#define   DCREG_SH_LAYER0_DMA_SRAM_SIZE_VALUE_EX_KBYTE160                   0x04
#define   DCREG_SH_LAYER0_DMA_SRAM_SIZE_VALUE_EX_KBYTE192                   0x05

