#define   DCREG_SH_LAYER1_ALPHA_BLEND_CONFIG_EX_ALPHA_BLEND_FAST_MODE_DST_OVER 0x4
#define   DCREG_SH_LAYER1_ALPHA_BLEND_CONFIG_EX_ALPHA_BLEND_FAST_MODE_SRC_IN 0x5
