#define DCREG_SH_LAYER4_DMA_MODE_WriteMask                            0x0000007F
#define DCREG_SH_LAYER4_DMA_MODE_ResetValue                           0x00000010

/* Normal mode: read full image, don’t support ROI. One ROI mode: read one  **
** ROI region in one image. Two ROI mode: read two ROI regions in one image.  **
** Skip mode: skip the ROI region in one image. Extend layer mode: read       **
** image0 and image1, don’t support ROI. Extend layer ex mode: read ROI     **
** region from image0 and read exrended ROI region from image1.               */
#define DCREG_SH_LAYER4_DMA_MODE_VALUE                                       2:0
#define   DCREG_SH_LAYER4_DMA_MODE_VALUE_NORMAL                              0x0
#define   DCREG_SH_LAYER4_DMA_MODE_VALUE_ONE_ROI                             0x1
#define   DCREG_SH_LAYER4_DMA_MODE_VALUE_TWO_ROI                             0x2
#define   DCREG_SH_LAYER4_DMA_MODE_VALUE_SKIP                                0x3
#define   DCREG_SH_LAYER4_DMA_MODE_VALUE_EXTEND_LAYER                        0x4
#define   DCREG_SH_LAYER4_DMA_MODE_VALUE_EXTEND_LAYER_EX                     0x5

/* Exlayer and exlayer_ex support 2~4 img number. */
#define DCREG_SH_LAYER4_DMA_MODE_EX_NUM                                      6:3
#define   DCREG_SH_LAYER4_DMA_MODE_EX_NUM_NUM2                               0x2
#define   DCREG_SH_LAYER4_DMA_MODE_EX_NUM_NUM3                               0x3
#define   DCREG_SH_LAYER4_DMA_MODE_EX_NUM_NUM4                               0x4

/* Register dcregShLayer4DmaSramSize **
** ~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~ */

/* Each layer needs some sram when this layer works.  This register is used   **
** to specify the dma sram size for this layer.  Dma sram unit size has 64k   **
** bytes and 32k bytes size.  Dma sram unit size refers to                    **
** Vivante.*.Hardware.Architecture.and.Features.                              */

#define DCREG_SH_LAYER4_DMA_SRAM_SIZE_Address                           0x028290
#define DCREG_SH_LAYER4_DMA_SRAM_SIZE_Count                                    1
#define DCREG_SH_LAYER4_DMA_SRAM_SIZE_WriteMask                       0x0000FFFF
#define DCREG_SH_LAYER4_DMA_SRAM_SIZE_ResetValue                      0x00000000

/* 64KBytes: Specify 64k bytes sram size. 128KBytes: Specify 128k bytes sram  **
** size. 192KBytes: Specify 192k bytes sram size. 256KBytes: Specify 256k     **
** bytes sram size. 320KBytes: Specify 320k bytes sram size. 384KBytes:       **
** Specify 384k bytes sram size.                                              */
