#define   DCREG_SH_LAYER4_DMA_SRAM_SIZE_VALUE_KBYTE64                       0x00
#define   DCREG_SH_LAYER4_DMA_SRAM_SIZE_VALUE_KBYTE128                      0x01
#define   DCREG_SH_LAYER4_DMA_SRAM_SIZE_VALUE_KBYTE192                      0x02
#define   DCREG_SH_LAYER4_DMA_SRAM_SIZE_VALUE_KBYTE256                      0x03
#define   DCREG_SH_LAYER4_DMA_SRAM_SIZE_VALUE_KBYTE320                      0x04
#define   DCREG_SH_LAYER4_DMA_SRAM_SIZE_VALUE_KBYTE384                      0x05

/* 32KBytes: Specify 32k bytes sram size. 64KBytes: Specify 64k bytes sram    **
** size. 96KBytes: Specify 96k bytes sram size. 128KBytes: Specify 128k bytes **
** sram size. 160KBytes: Specify 160k bytes sram size. 192KBytes: Specify     **
** 192k bytes sram size.                                                      */
#define DCREG_SH_LAYER4_DMA_SRAM_SIZE_VALUE_EX                              15:8
#define   DCREG_SH_LAYER4_DMA_SRAM_SIZE_VALUE_EX_KBYTE32                    0x00
#define   DCREG_SH_LAYER4_DMA_SRAM_SIZE_VALUE_EX_KBYTE64                    0x01
