#define   DCREG_SH_LAYER4_DMA_SRAM_SIZE_VALUE_EX_KBYTE160                   0x04
#define   DCREG_SH_LAYER4_DMA_SRAM_SIZE_VALUE_EX_KBYTE192                   0x05

