/* Register dcregLayer6Config **
** ~~~~~~~~~~~~~~~~~~~~~~~~~~ */

/* Layer6 Configuration Register.  Layer6 attributes control.  This register  **
** is not buffered.                                                           */

#define DCREG_LAYER6_CONFIG_Address                                     0x030000
#define DCREG_LAYER6_CONFIG_Count                                              1
#define DCREG_LAYER6_CONFIG_WriteMask                                 0x0000000F
#define DCREG_LAYER6_CONFIG_ResetValue                                0x00000000

/* This field indicates register switch status.  OK means HW can copy the     **
** register from shadow side to active side at the beginning of the frame.    **
** Wait means HW cannot copy the register from shadow side to active side at  **
** the beginning of the frame.  This register programming is not done by SW.  **
**  We call the registers configured by SW directly shadow registers.  We     **
** call the registers used by HW active registers.                            */
#define DCREG_LAYER6_CONFIG_REG_SWITCH                                       0:0
#define   DCREG_LAYER6_CONFIG_REG_SWITCH_WAIT                                0x0
#define   DCREG_LAYER6_CONFIG_REG_SWITCH_OK                                  0x1

/* Reset Layer6 Registers to default value. This bit is WRITE ONLY.  */
#define DCREG_LAYER6_CONFIG_RESET                                            1:1
#define   DCREG_LAYER6_CONFIG_RESET_RESET                                    0x1

/* Force HW copy the shadow register to active register directly.  */
#define DCREG_LAYER6_CONFIG_FORCE_FLIP                                       2:2

/* AxiBurstLenSel.  */
